forge solve(a, b) {
  sustain b > 0 {
    a % b -> r
    a -> b
    r -> a
  }
  give a
}
emit solve(12, 8)

forge solve(n) {
  when n = 0 { give 0 }
  when n = 1 { give 1 }
  0 -> a
  1 -> b
  sustain n > 1 {
    a + b -> c
    b -> a
    c -> b
    n - 1 -> n
  }
  give b
}
emit solve(10)

forge solve(n) {
  1 -> result
  walk i across range(1, n + 1) {
    result * i -> result
  }
  give result
}
emit solve(5)

forge solve(w) {
  count(w) -> len
  0 -> i
  sustain i < len {
    w @ i -> left
    len - 1 - i -> right_idx
    w @ right_idx -> right
    when left = right {
      i + 1 -> i
    } otherwise {
      give no
      halt
    }
  }
  give yes
}
emit solve("racecar")
emit solve("hello")

forge gcd(a, b) {
  sustain b > 0 {
    a % b -> r
    a -> b
    r -> a
  }
  give a
}

forge solve(a, b) {
  gcd(a, b) -> common
  when common = 0 { give 0 } otherwise {
    a * b -> product
    product / common -> lcm
    give lcm
  }
}

emit solve(12, 18)

forge solve(xs) {
  xs @ 0 -> max_val
  walk x across xs {
    when x > max_val { x -> max_val }
  }
  give max_val
}
emit solve([3, 7, 2, 9, 1])

forge solve(xs) {
  walk idx across range(count(xs) - 1) {
    xs @ idx -> current
    xs @ (idx + 1) -> next
    when current > next { give no }
  }
  give yes
}
emit solve([1, 2, 3, 4, 5])

forge solve(w, ch) {
  0 -> count
  walk c across chars(w) {
    when c = ch { count + 1 -> count }
  }
  give count
}
emit solve("hello", "l")

forge solve(b, e) {
  1 -> result
  sustain e > 0 {
    b * result -> result
    e - 1 -> e
  }
  give result
}
emit solve(2, 3)

forge index_of(xs, target) {
  0 -> i
  walk x across xs {
    when x = target { give i }
    i + 1 -> i
  }
  give -1
}

forge solve(xs) {
  [] -> keys
  [] -> counts
  walk it across xs {
    index_of(keys, it) -> pos
    when pos = -1 {
      push(keys, it) -> keys
      push(counts, 1) -> counts
    } otherwise {
      [] -> newcounts
      0 -> j
      walk c across counts {
        when j = pos { push(newcounts, c + 1) -> newcounts }
        otherwise { push(newcounts, c) -> newcounts }
        j + 1 -> j
      }
      newcounts -> counts
    }
  }
  counts @ 0 -> maxc
  0 -> j
  walk c across counts {
    when c > maxc { c -> maxc }
    j + 1 -> j
  }
  give maxc
}
emit solve([1, 2, 2, 3, 3, 3])

forge solve(xs) {
  walk idx across range(count(xs)) {
    xs @ idx -> current
    0 -> j
    walk item across slice(xs, 0, idx) {
      when item = current { give current }
      j + 1 -> j
    }
  }
  give void
}
emit solve([3, 1, 4, 1, 5, 9])
